export const OPENCODE_SIDECAR_PLUGIN_PATH = ".opencode/plugins/code-agent-plusplus.ts";

export function opencodeSidecarPluginTemplate(): string {
  return String.raw`/**
 * Code Agent++ OpenCode Sidecar Plugin
 *
 * Generated by \`capp\`. Edit only when you want to customize how OpenCode
 * presents the Code Agent++ harness inside this repository.
 */

import { appendFileSync, mkdirSync } from "node:fs";
import { spawnSync } from "node:child_process";
import { createHash } from "node:crypto";
import path from "node:path";

export const CodeAgentPlusPlusSidecar = async ({ directory, worktree, client }) => {
  const eventLog = path.join(directory, ".agent-context", "traces", "opencode-sidecar-events.jsonl");
  const VERIFY_DEBOUNCE_MS = 2000;
  let dirty = false;
  let verifying = false;
  let lastVerifyAt = 0;
  const toolStarts = new Map();

  function record(type, payload = {}) {
    try {
      mkdirSync(path.dirname(eventLog), { recursive: true });
      appendFileSync(
        eventLog,
        JSON.stringify({
          type,
          ts: new Date().toISOString(),
          directory,
          worktree,
          ...payload
        }) + "\n",
        "utf8"
      );
    } catch {
      // The sidecar must never break OpenCode. Verification can still run manually.
    }
  }

  function log(level, message, extra = {}) {
    record("sidecar.log", { level, message, ...extra });
    try {
      client?.app?.log?.({
        service: "code-agent-plusplus",
        level,
        message,
        extra
      });
    } catch {
      // Structured logging is best-effort and must never interrupt OpenCode.
    }
  }

  function commandFromTool(tool, args) {
    if (!args || typeof args !== "object") return null;
    if (typeof args.command === "string") return args.command;
    if (typeof args.cmd === "string") return args.cmd;
    if (typeof args.shell === "string") return args.shell;
    if (typeof args.input === "string" && /^(bash|shell|terminal|run)$/i.test(String(tool ?? ""))) return args.input;
    return null;
  }

  function pathsFromTool(args) {
    if (!args || typeof args !== "object") return [];
    const values = [];
    for (const key of ["path", "file", "filepath", "filePath", "target", "destination"]) {
      if (typeof args[key] === "string") values.push(args[key]);
    }
    if (Array.isArray(args.files)) {
      for (const file of args.files) if (typeof file === "string") values.push(file);
    }
    return values;
  }

  function hashText(text) {
    return createHash("sha256").update(String(text ?? "")).digest("hex");
  }

  function stableJson(value) {
    try {
      return JSON.stringify(value ?? null);
    } catch {
      return String(value);
    }
  }

  function toolKey(tool, args) {
    return String(tool ?? "unknown") + ":" + hashText(stableJson(args));
  }

  function gitOutput(args) {
    const result = spawnSync("git", args, {
      cwd: directory,
      encoding: "utf8",
      shell: process.platform === "win32"
    });
    return [
      "$ git " + args.join(" "),
      "status=" + (typeof result.status === "number" ? result.status : "unknown"),
      typeof result.stdout === "string" ? result.stdout : "",
      typeof result.stderr === "string" ? result.stderr : "",
      result.error?.message ?? ""
    ].join("\n");
  }

  function currentWorkingTreeHash() {
    const pathspec = ["--", ".", ":(exclude).agent-context/**", ":(exclude)AGENTS.md"];
    return hashText([gitOutput(["status", "--porcelain=v1", "--untracked-files=all", ...pathspec]), gitOutput(["diff", "--binary", ...pathspec])].join("\n"));
  }

  function outputText(output, keys) {
    for (const key of keys) {
      const value = output?.[key] ?? output?.properties?.[key];
      if (typeof value === "string") return value;
    }
    return "";
  }

  function exitCodeFromOutput(output) {
    for (const key of ["exitCode", "status", "code"]) {
      const value = output?.[key] ?? output?.properties?.[key];
      if (typeof value === "number") return value;
      if (typeof value === "string" && /^-?\d+$/.test(value)) return Number.parseInt(value, 10);
    }
    return null;
  }

  function runCommandGuard(tool, args) {
    const command = commandFromTool(tool, args);
    const paths = pathsFromTool(args);
    if (!command && paths.length === 0) return;

    const cliArgs = ["sidecar", "check-command", directory, "--json"];
    if (command) cliArgs.push("--command", command);
    else cliArgs.push("--command", "path-check");
    for (const file of paths) cliArgs.push("--path", file);

    const check = spawnSync("capp", cliArgs, {
      cwd: directory,
      encoding: "utf8",
      shell: process.platform === "win32"
    });
    record("sidecar.check-command", { tool, command, paths, exitCode: check.status ?? 1 });
    if ((check.status ?? 1) !== 0) {
      const output = (check.stdout || check.stderr || "Code Agent++ blocked a command or protected path.").trim();
      log("error", "blocked tool execution", { tool, command, paths });
      throw new Error(output);
    }
    log("debug", "tool execution allowed", { tool, command, paths });
  }

  function rememberToolStart(tool, args) {
    toolStarts.set(toolKey(tool, args), {
      startedAt: new Date().toISOString(),
      workingTreeHashBefore: currentWorkingTreeHash()
    });
  }

  function recordToolAfter(input, output) {
    try {
      const tool = input?.tool ?? input?.name ?? "unknown";
      const args = input?.args ?? input?.arguments ?? {};
      const command = commandFromTool(tool, args);
      const paths = pathsFromTool(args);
      const key = toolKey(tool, args);
      const started = toolStarts.get(key) ?? { startedAt: new Date().toISOString(), workingTreeHashBefore: currentWorkingTreeHash() };
      toolStarts.delete(key);

      const cliArgs = [
        "sidecar",
        "record-tool",
        directory,
        "--json",
        "--tool",
        String(tool),
        "--exit-code",
        String(exitCodeFromOutput(output) ?? 0),
        "--started-at",
        started.startedAt,
        "--finished-at",
        new Date().toISOString(),
        "--working-tree-hash-before",
        started.workingTreeHashBefore,
        "--working-tree-hash-after",
        currentWorkingTreeHash()
      ];
      if (command) cliArgs.push("--command", command);
      const sessionId = input?.sessionID ?? input?.sessionId ?? output?.sessionID ?? output?.sessionId;
      if (sessionId) cliArgs.push("--session-id", String(sessionId));
      const stdout = outputText(output, ["stdout", "output", "text"]);
      const stderr = outputText(output, ["stderr", "error"]);
      if (stdout) cliArgs.push("--stdout", stdout);
      if (stderr) cliArgs.push("--stderr", stderr);
      for (const file of paths) cliArgs.push("--path", file);

      const recordResult = spawnSync("capp", cliArgs, {
        cwd: directory,
        encoding: "utf8",
        shell: process.platform === "win32",
        maxBuffer: 10 * 1024 * 1024
      });
      record("sidecar.record-tool", { tool, command, paths, exitCode: recordResult.status ?? 1 });
      if ((recordResult.status ?? 1) !== 0) {
        log("debug", "tool evidence record failed", { tool, command, status: recordResult.status ?? 1 });
      }
    } catch (error) {
      log("debug", "tool evidence record failed", { message: error instanceof Error ? error.message : String(error) });
    }
  }

  function markDirty(type, payload = {}) {
    dirty = true;
    record(type, payload);
    log("debug", "repository marked dirty", { type, ...payload });
  }

  function maybeVerifyOnIdle() {
    const now = Date.now();
    if (!dirty) {
      log("debug", "idle verification skipped", { reason: "clean" });
      return;
    }
    if (verifying) {
      log("debug", "idle verification skipped", { reason: "already verifying" });
      return;
    }
    if (now - lastVerifyAt < VERIFY_DEBOUNCE_MS) {
      log("debug", "idle verification skipped", { reason: "debounced", elapsedMs: now - lastVerifyAt });
      return;
    }

    verifying = true;
    dirty = false;
    try {
      const verify = spawnSync("capp", ["sidecar", "verify", directory, "--quiet"], {
        cwd: directory,
        encoding: "utf8",
        shell: process.platform === "win32"
      });
      record("sidecar.verify", { exitCode: verify.status ?? 1 });
      if ((verify.status ?? 1) !== 0) {
        const output = (verify.stdout || verify.stderr || "Code Agent++ sidecar found blockers. Run capp report.").trim();
        log("error", "sidecar verification blocked", { exitCode: verify.status ?? 1 });
        console.log(output);
      } else {
        log("debug", "sidecar verification passed");
      }
    } finally {
      verifying = false;
      lastVerifyAt = Date.now();
    }
  }

  return {
    name: "code-agent-plusplus-sidecar",
    "tool.execute.before": async ({ tool, args }) => {
      rememberToolStart(tool, args);
      runCommandGuard(tool, args);
    },
    "tool.execute.after": async (input, output) => {
      recordToolAfter(input, output);
    },
    event: async ({ event }) => {
      const type = event?.type;
      if (event?.type === "session.created") {
        record("session.created");
        log("debug", "sidecar active", { directory, worktree });
      }

      if (type === "file.edited") {
        const file = event?.properties?.file ?? event?.properties?.path ?? event?.file ?? event?.path ?? "unknown";
        markDirty("file.edited", { file });
      }

      if (type === "file.watcher.updated") {
        const file = event?.properties?.file ?? event?.properties?.path ?? event?.file ?? event?.path ?? "unknown";
        markDirty("file.watcher.updated", { file });
      }

      if (type === "session.idle") {
        record("session.idle");
        maybeVerifyOnIdle();
      }
    }
  };
};
`;
}
